const regex = /j(\d+): jugador_insert\(data:\{([^}]+)\}\)/g;

const result = {};

let match;

while ((match = regex.exec(input)) !== null) {
  const index = match[1];
  const dataString = match[2];

  const obj = {};

  dataString.split(" ").forEach(part => {
    const [key, value] = part.split(":");
    if (!key || !value) return;

    obj[key] = value.replace(/"/g, "");
  });

  if (obj.numeroCamiseta) {
    obj.numeroCamiseta = Number(obj.numeroCamiseta);
  }

  result[`j${index}`] = obj;
}

// ordenar
const ordered = Object.keys(result)
  .sort((a, b) => Number(a.slice(1)) - Number(b.slice(1)))
  .reduce((acc, key) => {
    acc[key] = result[key];
    return acc;
  }, {});

fs.writeFileSync("jugadores.json", JSON.stringify(ordered, null, 2));

